  it("size=5 first cell l=1 i=1", () => { const m=buildRiskMatrix(5); expect(m.cells[0][0].likelihood).toBe(1); expect(m.cells[0][0].impact).toBe(1); });
  it("size=5 last cell l=size i=size", () => { const m=buildRiskMatrix(5); const last=m.cells[4][4]; expect(last.likelihood).toBe(5); expect(last.impact).toBe(5); });
  it("size=5 all scores positive", () => { buildRiskMatrix(5).cells.forEach(r=>r.forEach(c=>expect(c.score).toBeGreaterThan(0))); });
  it("defaults to size=5", () => { const m=buildRiskMatrix(); expect(m.size).toBe(5); expect(m.cells.length).toBe(5); });
  it("custom thresholds stored", () => { const ct={low:1,medium:4,high:12}; expect(buildRiskMatrix(5,ct).thresholds).toEqual(ct); });
  it("5x5 cell[0][0] score=1", () => { expect(buildRiskMatrix(5).cells[0][0].score).toBe(1); });
  it("5x5 cell[0][1] score=2", () => { expect(buildRiskMatrix(5).cells[0][1].score).toBe(2); });
