describe("isValidDimension", () => {
  it("1 => true", () => { expect(isValidDimension(1)).toBe(true); });
  it("2 => true", () => { expect(isValidDimension(2)).toBe(true); });
  it("3 => true", () => { expect(isValidDimension(3)).toBe(true); });
  it("4 => true", () => { expect(isValidDimension(4)).toBe(true); });
  it("5 => true", () => { expect(isValidDimension(5)).toBe(true); });
  it("0 => false", () => { expect(isValidDimension(0)).toBe(false); });
  it("6 => false", () => { expect(isValidDimension(6)).toBe(false); });
  it("-1 => false", () => { expect(isValidDimension(-1)).toBe(false); });
  it("1.5 => false", () => { expect(isValidDimension(1.5)).toBe(false); });
  it("10 => false", () => { expect(isValidDimension(10)).toBe(false); });
  it("100 => false", () => { expect(isValidDimension(100)).toBe(false); });
  it("NaN => false", () => { expect(isValidDimension(NaN)).toBe(false); });
  it("Infinity => false", () => { expect(isValidDimension(Infinity)).toBe(false); });
  it("-Infinity => false", () => { expect(isValidDimension(-Infinity)).toBe(false); });
  it("isValidDimension(-5) = false", () => { expect(isValidDimension(-5)).toBe(false); });
  it("isValidDimension(-4) = false", () => { expect(isValidDimension(-4)).toBe(false); });
  it("isValidDimension(-3) = false", () => { expect(isValidDimension(-3)).toBe(false); });
  it("isValidDimension(-2) = false", () => { expect(isValidDimension(-2)).toBe(false); });
  it("isValidDimension(-1) = false", () => { expect(isValidDimension(-1)).toBe(false); });
  it("isValidDimension(0) = false", () => { expect(isValidDimension(0)).toBe(false); });
  it("isValidDimension(1) = true", () => { expect(isValidDimension(1)).toBe(true); });
  it("isValidDimension(2) = true", () => { expect(isValidDimension(2)).toBe(true); });
  it("isValidDimension(3) = true", () => { expect(isValidDimension(3)).toBe(true); });
  it("isValidDimension(4) = true", () => { expect(isValidDimension(4)).toBe(true); });
  it("isValidDimension(5) = true", () => { expect(isValidDimension(5)).toBe(true); });
  it("isValidDimension(6) = false", () => { expect(isValidDimension(6)).toBe(false); });
  it("isValidDimension(7) = false", () => { expect(isValidDimension(7)).toBe(false); });
  it("isValidDimension(8) = false", () => { expect(isValidDimension(8)).toBe(false); });
  it("isValidDimension(9) = false", () => { expect(isValidDimension(9)).toBe(false); });
  it("isValidDimension(10) = false", () => { expect(isValidDimension(10)).toBe(false); });
});

